char* ReadFile(const char* filename) {
  char* buffer = NULL;
  int file_size, read_size;
  FILE* file = fopen(filename, "r");
  if (!file)
    return NULL;

  fseek(file, 0, SEEK_END);

  file_size = ftell(file);
  rewind(file);
  buffer = (char*)malloc(sizeof(char) * (file_size + 1));
  read_size = fread(buffer, sizeof(char), file_size, file);
  buffer[file_size] = '\0';
  if (file_size != read_size) {
    free(buffer);
    buffer = NULL;
  }
  return buffer;
}

void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++)
    flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++)
    flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove)
    flushed_printf("\b");
}

void show_progress_done(void) {
  flushed_printf("\n");
}

double get_event_duration(cudaEvent_t start, cudaEvent_t stop) {
  float milliseconds = 0;
  cudaEventElapsedTime(&milliseconds, start, stop);
  return milliseconds;
}

